mapper.select:
SELECT * FROM performance
WHERE approval_status = 'PUBLISHED'
AND category = #{category}
AND status = #{status}

    AND (title LIKE CONCAT('%', #{keyword}, '%')
      OR venue_name LIKE CONCAT('%', #{keyword}, '%'))

ORDER BY ticket_open_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM performance
WHERE approval_status = 'PUBLISHED'
AND category = #{category}
AND status = #{status}

    AND (title LIKE CONCAT('%', #{keyword}, '%')
      OR venue_name LIKE CONCAT('%', #{keyword}, '%'))

mapper.insert:
INSERT INTO performance ( api_perf_id, title, category, venue_id, venue_name, description, poster_url, total_seats, ticket_open_at, start_date, end_date, status, stage_config_id, promoter_id, approval_status ) VALUES ( #{apiPerfId}, #{title}, #{category}, #{venueId}, #{venueName}, #{description}, #{posterUrl}, #{totalSeats}, #{ticketOpenAt}, #{startDate}, #{endDate}, #{status}, #{stageConfigId}, #{promoterId},
#{approvalStatus} 'DRAFT'
)

mapper.update:
UPDATE performance
title = #{title}, status = #{status}, total_seats = #{totalSeats}, stage_config_id = #{stageConfigId}, description = #{description}, poster_url = #{posterUrl}, venue_name = #{venueName}, venue_id = #{venueId}, start_date = #{startDate}, end_date = #{endDate}, ticket_open_at = #{ticketOpenAt},
WHERE performance_id = #{performanceId}

mapper.select:
SELECT p.*,
       pr.company_name AS promoter_company_name
FROM performance p
LEFT JOIN promoter pr ON p.promoter_id = pr.promoter_id
WHERE p.promoter_id = #{promoterId}

    AND p.approval_status = #{approvalStatus}

ORDER BY p.created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM performance
WHERE promoter_id = #{promoterId}

    AND approval_status = #{approvalStatus}

SELECT p.*, pr.company_name AS promoter_company_name FROM performance p LEFT JOIN promoter pr ON p.promoter_id = pr.promoter_id
WHERE p.approval_status = #{approvalStatus}
ORDER BY p.created_at DESC LIMIT #{limit} OFFSET #{offset}
